import{_ as o,o as e,c as a,a2 as u}from"./chunks/framework.Crpw6aS5.js";const i=JSON.parse('{"title":"保险浮存金","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/保险浮存金.md","filePath":"05_quotes/by-theme/保险浮存金.md"}'),r={name:"05_quotes/by-theme/保险浮存金.md"};function l(q,t,c,_,p,s){return e(),a("div",null,[...t[0]||(t[0]=[u('<h1 id="保险浮存金" tabindex="-1">保险浮存金 <a class="header-anchor" href="#保险浮存金" aria-label="Permalink to &quot;保险浮存金&quot;">​</a></h1><blockquote><p>&quot;浮存金是伯克希尔最重要的低成本资金来源。我们的保险业务不仅仅是一个生意，它是整个集团的秘密武器。&quot;——巴菲特</p></blockquote><p>浮存金是伯克希尔帝国建立的独特资金优势。</p><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;浮存金是我们保险业务提供给集团的无息资金。收取保费在理赔之前，这段时间的资金就是我们的低成本资本。&quot;</p></blockquote><blockquote><p>&quot;重要的是浮存金的规模，也同样重要的是它的成本。如果浮存金成本为负，那就意味着我们实际上是通过保险业务在赚钱，同时获得了免费资金。&quot;</p></blockquote><blockquote><p>&quot;伯克希尔的保险业务是我们投资能力的根基。正因为有了稳定的浮存金，我们才能在没有资金压力的情况下进行长期投资。&quot;</p></blockquote><blockquote><p>&quot;好年份的承保利润让我们获得低成本浮存金，坏年份我们承担损失。长期来看，浮存金成本应该接近于零甚至为负。&quot;</p></blockquote><blockquote><p>&quot;国家赔偿公司的浮存金成本多年来一直为负——这意味着我们的保险业务在赚钱的同时，还为我们提供了免费资金用于投资。&quot;</p></blockquote><hr><h2 id="出处年份" tabindex="-1">出处年份 <a class="header-anchor" href="#出处年份" aria-label="Permalink to &quot;出处年份&quot;">​</a></h2><p>1977年 · 1995年 · 1996年 · 2005年 · 2010年 · 2020年</p>',13)])])}const h=o(r,[["render",l]]);export{i as __pageData,h as default};
